62	// TestMirrorBundle_LocalDirRoundtrip verifies the local-dir backend can
63	// upload a bundle, append an index row, and fetch the bundle back so the
64	// bytes match the original.
65	func TestMirrorBundle_LocalDirRoundtrip(t *testing.T) {
66		projectRoot := t.TempDir()
67		const attemptID = "20260418T061717-1993d293"
68		const beadID = "ddx-mirror-roundtrip"
69	
70		// Build the bundle on disk.
71		bundleDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
72		if err := os.MkdirAll(filepath.Join(bundleDir, "embedded"), 0o755); err != nil {
73			t.Fatal(err)
74		}
75		files := map[string]string{
76			"manifest.json":            `{"attempt_id":"` + attemptID + `"}`,
77			"prompt.md":                "task: do the thing",
78			"result.json":              `{"status":"success"}`,
79			"usage.json":               `{"tokens":42}`,
80			"embedded/agent-001.jsonl": "trace line 1\ntrace line 2\n",
81		}
82		for name, body := range files {
83			path := filepath.Join(bundleDir, name)
84			if err := os.WriteFile(path, []byte(body), 0o644); err != nil {
85				t.Fatalf("seeding %s: %v", name, err)
86			}
87		}
88	
89		// Mirror destination — outside the project root.
90		mirrorRoot := t.TempDir()
91		tpl := filepath.Join(mirrorRoot, "{project}/{attempt_id}")
92	
93		cfg := &config.ExecutionsMirrorConfig{
94			Kind: "local",
95			Path: tpl,
96		}
97		entry, err := MirrorBundle(MirrorRequest{
98			ProjectRoot: projectRoot,
99			AttemptID:   attemptID,
100			BeadID:      beadID,
101			BundleDir:   bundleDir,
102			Cfg:         cfg,
103		})
104		if err != nil {
105			t.Fatalf("MirrorBundle: %v", err)
106		}
107	
108		expectedDest := filepath.Join(mirrorRoot, filepath.Base(projectRoot), attemptID)
109		if entry.MirrorURI != expectedDest {
110			t.Errorf("MirrorURI = %q, want %q", entry.MirrorURI, expectedDest)
111		}
112		if entry.AttemptID != attemptID || entry.BeadID != beadID {
113			t.Errorf("entry ids: got attempt=%q bead=%q", entry.AttemptID, entry.BeadID)
114		}
115		if entry.ByteSize == 0 {
116			t.Error("ByteSize must be non-zero after upload")
117		}
118		if entry.Kind != "local" {
119			t.Errorf("Kind = %q, want local", entry.Kind)
120		}
121	
122		// Index file appended.
123		indexPath := filepath.Join(projectRoot, ExecutionsMirrorIndexFile)
124		indexData, err := os.ReadFile(indexPath)
125		if err != nil {
126			t.Fatalf("reading index: %v", err)
127		}
128		if !strings.Contains(string(indexData), attemptID) {
129			t.Errorf("index missing attempt id, got: %s", indexData)
130		}
131	
132		// LookupMirrorEntry round-trip.
133		got, err := LookupMirrorEntry(projectRoot, attemptID)
134		if err != nil {
135			t.Fatalf("LookupMirrorEntry: %v", err)
136		}
137		if got == nil || got.MirrorURI != expectedDest {
138			t.Fatalf("LookupMirrorEntry: %#v", got)
139		}
140	
141		// Fetch back into a different destination and verify byte-equal.
142		restored := t.TempDir()
143		backend, err := NewMirrorBackend("local")
144		if err != nil {
145			t.Fatalf("NewMirrorBackend: %v", err)
146		}
147		if err := backend.Fetch(entry.MirrorURI, restored); err != nil {
148			t.Fatalf("Fetch: %v", err)
149		}
150		for name, want := range files {
151			got, err := os.ReadFile(filepath.Join(restored, name))
152			if err != nil {
153				t.Errorf("restored %s: %v", name, err)
154				continue
155			}
156			if string(got) != want {
157				t.Errorf("restored %s mismatch:\n got: %q\nwant: %q", name, got, want)
158			}
159		}
160	
161		// Belt-and-suspenders: directory tree hashes match.
162		if h1, h2 := dirHash(t, bundleDir), dirHash(t, restored); h1 != h2 {
163			t.Errorf("dir hash mismatch after roundtrip: original=%s restored=%s", h1, h2)
164		}
165	}
