285	func dirHash(t *testing.T, root string) string {
286		t.Helper()
287		h := sha256.New()
288		walked := []string{}
289		if err := filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
290			if err != nil {
291				return err
292			}
293			if info.IsDir() {
294				return nil
295			}
296			rel, _ := filepath.Rel(root, path)
297			walked = append(walked, rel)
298			return nil
299		}); err != nil {
300			t.Fatal(err)
301		}
302		// Stable order.
303		for _, rel := range walked {
304			f, err := os.Open(filepath.Join(root, rel))
305			if err != nil {
306				t.Fatal(err)
307			}
308			_, _ = io.WriteString(h, rel+"\x00")
309			_, _ = io.Copy(h, f)
310			_ = f.Close()
311		}
312		return hex.EncodeToString(h.Sum(nil))
313	}
