15	
16	// ExecutionsMirrorIndexFile is the local pointer file that lists every
17	// successfully mirrored bundle. One JSON object per line.
18	const ExecutionsMirrorIndexFile = ".ddx/executions/mirror-index.jsonl"
19	
20	// ExecutionsMirrorLogFile records mirror upload attempts and failures so
21	// operators can diagnose mirror-side issues without re-running execute-bead.
22	const ExecutionsMirrorLogFile = ".ddx/agent-logs/mirror.log"
23	
24	// MirrorIndexEntry is one row of the local mirror-index.jsonl pointer file.
25	type MirrorIndexEntry struct {
26		AttemptID  string    `json:"attempt_id"`
27		BeadID     string    `json:"bead_id,omitempty"`
28		MirrorURI  string    `json:"mirror_uri"`
29		UploadedAt time.Time `json:"uploaded_at"`
30		ByteSize   int64     `json:"byte_size"`
31		Kind       string    `json:"kind"`
32	}
33	
34	// MirrorBackend uploads and retrieves bundle directories.
35	type MirrorBackend interface {
36		// Kind returns the backend identifier (matches the configured kind, e.g. "local").
37		Kind() string
38		// Upload copies the resolved set of files in srcDir to a destination derived
39		// from the rendered destination URI/path. Returns the canonical mirror URI
40		// for the bundle along with the total bytes uploaded.
41		Upload(destURI, srcDir string, includeFilter func(relPath string) bool) (string, int64, error)
42		// Fetch downloads a previously mirrored bundle to destDir.
43		Fetch(mirrorURI, destDir string) error
44	}
45	
46	// MirrorRequest carries everything needed to mirror one execute-bead bundle.
47	type MirrorRequest struct {
48		ProjectRoot string
49		AttemptID   string
50		BeadID      string
51		BundleDir   string // absolute path to .ddx/executions/<attempt-id>/
52		Cfg         *config.ExecutionsMirrorConfig
53	}
54	
55	// allMirrorParts is the canonical default include list — every part of the
56	// bundle. Used when ExecutionsMirrorConfig.Include is empty.
57	var allMirrorParts = []string{"manifest", "prompt", "result", "usage", "checks", "embedded"}
58	
59	// fileForPart returns the relative bundle path (or directory prefix) for a
60	// part name. The "embedded" part is a directory; the rest are single files.
61	func fileForPart(part string) (string, bool) {
62		switch part {
63		case "manifest":
64			return "manifest.json", false
65		case "prompt":
66			return "prompt.md", false
67		case "result":
68			return "result.json", false
69		case "usage":
70			return "usage.json", false
71		case "checks":
72			return "checks.json", false
73		case "embedded":
74			return "embedded", true
75		}
76		return "", false
77	}
78	
79	// IncludeFilter returns a filter callable matching the include list. An empty
80	// list means everything is included.
81	func IncludeFilter(parts []string) func(string) bool {
82		if len(parts) == 0 {
83			parts = allMirrorParts
84		}
85		files := make(map[string]struct{})
86		dirs := make([]string, 0)
87		for _, p := range parts {
88			rel, isDir := fileForPart(strings.ToLower(strings.TrimSpace(p)))
89			if rel == "" {
90				continue
91			}
92			if isDir {
93				dirs = append(dirs, rel+string(filepath.Separator))
94			} else {
95				files[rel] = struct{}{}
96			}
97		}
98		return func(rel string) bool {
99			rel = filepath.ToSlash(rel)
100			// Map back to OS separators for the file lookup.
101			osRel := filepath.FromSlash(rel)
102			if _, ok := files[osRel]; ok {
103				return true
104			}
105			for _, prefix := range dirs {
106				pfx := filepath.ToSlash(prefix)
107				if strings.HasPrefix(rel, pfx) {
108					return true
109				}
110			}
111			return false
112		}
113	}
