115	// RenderMirrorPath substitutes the {project}, {attempt_id}, {date}, {bead_id}
116	// placeholders in template. Unknown placeholders are left in place. The
117	// "{date}" expansion uses YYYY-MM-DD derived from the attempt id when it
118	// matches the standard "YYYYMMDDTHHMMSS-..." form, falling back to the
119	// current UTC date.
120	func RenderMirrorPath(template, projectName, attemptID, beadID string) string {
121		date := time.Now().UTC().Format("2006-01-02")
122		if len(attemptID) >= 8 && isAllDigits(attemptID[:8]) {
123			date = fmt.Sprintf("%s-%s-%s", attemptID[0:4], attemptID[4:6], attemptID[6:8])
124		}
125		r := strings.NewReplacer(
126			"{project}", projectName,
127			"{attempt_id}", attemptID,
128			"{date}", date,
129			"{bead_id}", beadID,
130		)
131		return r.Replace(template)
132	}
